import androidx.core.content.FileProvider
import org.json.JSONObject
import java.io.File
import java.io.FileOutputStream
import java.text.SimpleDateFormat
import java.util.*

class MainActivity : AppCompatActivity() {

    private lateinit var webView: WebView
    private var fileUploadCallback: ValueCallback<Array<Uri>>? = null
    private var cameraPhotoUri: Uri? = null
    
    private val cameraPermissionLauncher = registerForActivityResult(
        ActivityResultContracts.RequestPermission()
    ) { isGranted ->
        if (isGranted) {
            openCamera()
        } else {
            Toast.makeText(this, "Camera permission denied", Toast.LENGTH_SHORT).show()
        }
    }
    
    private val cameraLauncher = registerForActivityResult(
        ActivityResultContracts.TakePicture()
    ) { success ->
        if (success && cameraPhotoUri != null) {
            val imagePath = cameraPhotoUri.toString()
            webView.evaluateJavascript(
                "if(window.onCameraResult) window.onCameraResult('$imagePath');",
                null
            )
        } else {
            webView.evaluateJavascript(
                "if(window.onCameraResult) window.onCameraResult(null);",
                null
            )
        }
    }
    
    private val fileChooserLauncher = registerForActivityResult(
        ActivityResultContracts.StartActivityForResult()
    ) { result ->
        if (result.resultCode == Activity.RESULT_OK) {
            val data = result.data
            fileUploadCallback?.onReceiveValue(
                WebChromeClient.FileChooserParams.parseResult(result.resultCode, data)
            )
        } else {
            fileUploadCallback?.onReceiveValue(null)
        }
        fileUploadCallback = null
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        
        webView = WebView(this)
        setContentView(webView)
        
        setupWebView()
        createNotificationChannel()
        
        webView.loadUrl("https://your-web-app-url.com")
    }

    private fun setupWebView() {
        webView.settings.apply {
            javaScriptEnabled = true
            domStorageEnabled = true
            databaseEnabled = true
            cacheMode = WebSettings.LOAD_DEFAULT
            mixedContentMode = WebSettings.MIXED_CONTENT_ALWAYS_ALLOW
            allowFileAccess = true
            allowContentAccess = true
            javaScriptCanOpenWindowsAutomatically = true
        }
        
        webView.addJavascriptInterface(NativeBridge(this), "NativeBridge")
        
        webView.webViewClient = object : WebViewClient() {
            override fun onPageStarted(view: WebView?, url: String?, favicon: Bitmap?) {
                super.onPageStarted(view, url, favicon)
            }
            
            override fun onPageFinished(view: WebView?, url: String?) {
                super.onPageFinished(view, url)
            }
            
            override fun shouldOverrideUrlLoading(view: WebView?, url: String?): Boolean {
                return false
            }
        }
        
        webView.webChromeClient = object : WebChromeClient() {
            override fun onShowFileChooser(
                webView: WebView?,
                filePathCallback: ValueCallback<Array<Uri>>?,
                fileChooserParams: FileChooserParams?
            ): Boolean {
                fileUploadCallback?.onReceiveValue(null)
                fileUploadCallback = filePathCallback
                
                val intent = fileChooserParams?.createIntent()
                try {
                    fileChooserLauncher.launch(intent)
                } catch (e: Exception) {
                    fileUploadCallback = null
                    return false
                }
                return true
            }
        }
    }
    
    private fun createNotificationChannel() {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
            val channel = NotificationChannel(
                CHANNEL_ID,
                "App Notifications",
                NotificationManager.IMPORTANCE_DEFAULT
            ).apply {
                description = "Notifications from web app"
            }
            
            val notificationManager = getSystemService(NotificationManager::class.java)
            notificationManager.createNotificationChannel(channel)
        }
    }
    
    fun requestCameraAccess() {
        when {
            ContextCompat.checkSelfPermission(
                this,
                Manifest.permission.CAMERA
            ) == PackageManager.PERMISSION_GRANTED -> {
                openCamera()
            }
            else -> {
                cameraPermissionLauncher.launch(Manifest.permission.CAMERA)
            }
        }
    }
    
    private fun openCamera() {
        val photoFile = createImageFile()
        cameraPhotoUri = FileProvider.getUriForFile(
            this,
            "${packageName}.fileprovider",
            photoFile
        )
        cameraLauncher.launch(cameraPhotoUri)
    }
    
    private fun createImageFile(): File {
        val timeStamp = SimpleDateFormat("yyyyMMdd_HHmmss", Locale.US).format(Date())
        val storageDir = getExternalFilesDir(null)
        return File.createTempFile("JPEG_${timeStamp}_", ".jpg", storageDir)
    }
    
    fun showNotification(title: String, message: String) {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
            if (ContextCompat.checkSelfPermission(
                    this,
                    Manifest.permission.POST_NOTIFICATIONS
                ) != PackageManager.PERMISSION_GRANTED
            ) {
                ActivityCompat.requestPermissions(
                    this,
                    arrayOf(Manifest.permission.POST_NOTIFICATIONS),
                    NOTIFICATION_PERMISSION_CODE
                )
                return
            }
        }
        
        val builder = NotificationCompat.Builder(this, CHANNEL_ID)
            .setSmallIcon(android.R.drawable.ic_dialog_info)
            .setContentTitle(title)
            .setContentText(message)
            .setPriority(NotificationCompat.PRIORITY_DEFAULT)
            .setAutoCancel(true)
        
        with(NotificationManagerCompat.from(this)) {
            notify(notificationId++, builder.build())
        }
    }
    
    override fun onBackPressed() {
        if (webView.canGoBack()) {
            webView.goBack()
        } else {
            super.onBackPressed()
        }
    }
    
    companion object {
        private const val CHANNEL_ID = "web_app_channel"
        private const val NOTIFICATION_PERMISSION_CODE = 1001
        private var notificationId = 1
    }
}

class NativeBridge(private val activity: MainActivity) {
    
    @JavascriptInterface
    fun openCamera() {
        activity.runOnUiThread {
            activity.requestCameraAccess()
        }
    }
    
    @JavascriptInterface
    fun saveToLocalStorage(key: String, value: String): Boolean {
        return try {
            val prefs = activity.getSharedPreferences("WebAppStorage", Context.MODE_PRIVATE)
            prefs.edit().putString(key, value).apply()
            true
        } catch (e: Exception) {
            false
        }
    }
    
    @JavascriptInterface
    fun getFromLocalStorage(key: String): String? {
        return try {
            val prefs = activity.getSharedPreferences("WebAppStorage", Context.MODE_PRIVATE)
            prefs.getString(key, null)
        } catch (e: Exception) {
            null
        }
    }
    
    @JavascriptInterface
    fun removeFromLocalStorage(key: String): Boolean {
        return try {
            val prefs = activity.getSharedPreferences("WebAppStorage", Context.MODE_PRIVATE)
            prefs.edit().remove(key).apply()
            true
        } catch (e: Exception) {
            false
        }
    }
    
    @JavascriptInterface
    fun clearLocalStorage(): Boolean {
        return try {
            val prefs = activity.getSharedPreferences("WebAppStorage", Context.MODE_PRIVATE)
            prefs.edit().clear().apply()
            true
        } catch (e: Exception) {
            false
        }
    }
    
    @JavascriptInterface
    fun getAllStorageKeys(): String {
        return try {
            val prefs = activity.getSharedPreferences("WebAppStorage", Context.MODE_PRIVATE)
            val keys = prefs.all.keys.toList()
            JSONObject().apply {
                put("keys", keys)
            }.toString()
        } catch (e: Exception) {
            "{\"keys\":[]}"
        }
    }
    
    @JavascriptInterface
    fun showNotification(title: String, message: String) {
        activity.runOnUiThread {
            activity.showNotification(title, message)
        }
    }
    
    @JavascriptInterface
    fun showToast(message: String) {
        activity.runOnUiThread {
            Toast.makeText(activity, message, Toast.LENGTH_SHORT).show()
        }
    }
    
    @JavascriptInterface
    fun getDeviceInfo(): String {
        val info = JSONObject().apply {
            put("manufacturer", Build.MANUFACTURER)
            put("model", Build.MODEL)
            put("androidVersion", Build.VERSION.RELEASE)
            put("sdkVersion", Build.VERSION.SDK_INT)
            put("appVersion", try {
                activity.packageManager.getPackageInfo(activity.packageName, 0).versionName
            } catch (e: Exception) {
                "unknown"
            })
        }
        return info.toString()
    }
    
    @JavascriptInterface
    fun vibrate(milliseconds: Long) {
        activity.runOnUiThread {
            val vibrator = activity.getSystemService(Context.VIBRATOR_SERVICE) as android.os.Vibrator
            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
                vibrator.vibrate(
                    android.os.VibrationEffect.createOneShot(
                        milliseconds,
                        android.os.VibrationEffect.DEFAULT_AMPLITUDE
                    )
                )
            } else {
                @Suppress("DEPRECATION")
                vibrator.vibrate(milliseconds)
            }
        }
    }
    
    @JavascriptInterface
    fun shareContent(title: String, text: String, url: String) {
        activity.runOnUiThread {
            val shareIntent = Intent().apply {
                action = Intent.ACTION_SEND
                type = "text/plain"
                putExtra(Intent.EXTRA_SUBJECT, title)
                putExtra(Intent.EXTRA_TEXT, "$text\n$url")
            }
            activity.startActivity(Intent.createChooser(shareIntent, "Share via"))
        }
    }
    
    @JavascriptInterface
    fun isOnline(): Boolean {
        val connectivityManager = activity.getSystemService(Context.CONNECTIVITY_SERVICE) 
            as android.net.ConnectivityManager
        val network = connectivityManager.activeNetwork ?: return false
        val capabilities = connectivityManager.getNetworkCapabilities(network) ?: return false
        return capabilities.hasCapability(android.net.NetworkCapabilities.NET_CAPABILITY_INTERNET)
    }
    
    @JavascriptInterface
    fun getBatteryLevel(): Int {
        val batteryManager = activity.getSystemService(Context.BATTERY_SERVICE) 
            as android.os.BatteryManager
        return batteryManager.getIntProperty(android.os.BatteryManager.BATTERY_PROPERTY_CAPACITY)
    }
}